{
  "title": "ग्राउंडिंग बनाम मतिभ्रम",
  "group": "उन्नत",
  "options": [
    {
      "text": "सिस्टम प्रॉम्प्ट में मॉडल को \"मतिभ्रम मत करो\" कहें"
    },
    {
      "text": "अधिक आत्मविश्वासपूर्ण प्रतिक्रियाएँ उत्पन्न करने के लिए उच्च तापमान का उपयोग करें"
    },
    {
      "text": "प्राप्त स्रोत दस्तावेज़ प्रदान करें और मॉडल को उन्हें उद्धृत करने का निर्देश दें"
    },
    {
      "text": "बड़ा मॉडल उपयोग करें — मतिभ्रम केवल छोटे मॉडलों में होता है"
    }
  ],
  "questionProse": [
    "प्रोडक्शन AI सिस्टम में मतिभ्रम को कम करने की सबसे प्रभावी तकनीक है:"
  ],
  "explanationProse": [
    "मॉडल को मतिभ्रम न करने का निर्देश देना मतिभ्रम को नहीं रोकता — मॉडल के पास \"मैं यह बना रहा हूँ\" के लिए कोई विश्वसनीय आत्मनिरीक्षण संकेत नहीं है। इसका मतलब सिर्फ इतना है कि मॉडल आत्मविश्वास से आपको बताएगा कि वह चीज़ें नहीं बना रहा है जबकि वह चीज़ें बना रहा है।\n\n    वास्तव में क्या काम करता है: **ग्राउंडिंग**। मॉडल को सही उत्तर देने के लिए आवश्यक जानकारी दें, और उसे उसी जानकारी तक सीमित रखें:",
    "फिर आउटपुट को मान्य करें: जाँचें कि प्रतिक्रिया में दिए गए दावे प्राप्त संदर्भ में दिखाई देते हैं। यह उद्धरण ग्राउंडिंग जाँच है — कार्यान्वयन के लिए RAG मूल्यांकन चर्चा देखें।\n\n    बड़े मॉडल औसतन कम मतिभ्रम करते हैं, लेकिन सभी मॉडल मतिभ्रम करते हैं। ग्राउंडिंग शमन रणनीति है, मॉडल आकार नहीं।"
  ]
}
